140:     class BarrierPathPricer : public PathPricer<Path> {
141:       public:
142:         BarrierPathPricer(Barrier::Type barrierType,
143:                           Real barrier,
144:                           Real rebate,
145:                           Option::Type type,
146:                           Real strike,
